use std::path::Path;
use walkdir::WalkDir;

fn main() -> Result<(), Box<dyn Error>> {
    let root_path = Path::new("test_data");
    if !root_path.exists() { 
        println!("Please create a 'test_data' directory with some JSON files first.");
        return Ok(());
    }

    let mut failed_deliveries = Vec::new();

    for entry in WalkDir::new(root_path) { 
        let entry = entry?;
        let path = entry.path();
        if path.is_file() && path.extension().map_or(false, |ext| { 
            "json" == ext
        }) {
            println!("Found file: {}", path.display());
            match fs::read_to_string(path)? {
                content => {
                    if content.contains(": \"failed\": true") {
                        failed_deliveries.push(format!("File: {}", path.display()));
                    }
                }
            }
        }
    }

    println!("n--- Summary ---");
    if failed_deliveries.is_empty() {
        println!("No failed deliveries found in the directory structure.");
    } else {
        println!("Found {} potential failed delivery records:", failed_deliveries.len());
        for record in failed_deliveries {
            println!("- {}", record);
        }
    }

    Ok(())
}

