use std::path::{Path, PathBuf};
use walkdir::WalkDir;

fn main() {
    let target_directory = Path::new("./config_files");
    if !target_directory.exists() || !target_directory.is_dir() {
        println!("Error: Target directory '{}' does not exist.", target_directory.display());
        return;
    }

    let allowed_extension = ".cfg";

    for entry in WalkDir::new(target_directory)
        .into_iter()
        .filter_map(|e| e.ok())
    {
        let path = entry.path();
        if path.is_file() && path.extension().map_or(false, |ext| ext == allowed_extension.trim_start_matches('.')) {
            println!("Found config file: {}", path.display());
        }
    }
}

