use std::fs;
use std::path::{Path, PathBuf};
use walkdir::WalkDir;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let start_dir = Path::new("./src_content");
    if !start_dir.exists() {
        println!("Creating dummy directory structure for demonstration...");
        fs::create_dir_all(Path::new("./src_content/about"))?;
        fs::write(Path::new("./src_content/index.html"), "<!DOCTYPE html></html>")?;
        fs::write(Path::new("./src_content/about/contact.md"), "# Contact")?;
        fs::create_dir_all(Path::new("./src_content/assets"))?;
    } else {
        let mut html_files = Vec::new();
        for entry in WalkDir::new(start_dir).into_iter().filter_map(|e| e.ok()) {
            let path = entry.path();
            if path.is_file() && path.extension().map_or(false, |ext| ext == "html") {
                println!("Found HTML file: {}", path.display());
                html_files.push(path.to_owned());
            }
        }

        if html_files.is_empty() {
            println!("No HTML files found in the directory structure.");
        } else {
            println!("Successfully collected {} HTML file paths for processing.", html_files.len());
        }
    }
    Ok(())
}

use std::fs;
use std::path::Path;
use walkdir::WalkDir;

fn main() -> std::io::Result<()> {
    let start_path = Path::new("test_logs");
    if !start_path.exists() {
        println!("Creating dummy directory structure for testing...");
        std::fs::create_dir_all(start_path.join("sub1"))?;
        std::fs::write(start_path.join("app.log"), "initial content")?;
        std::fs::write(start_path.join("sub1").join("service.log"), "another log entry")?;
    }

    println!("--- Traversing directory structure ---");
    let walker = WalkDir::new(start_path);
    for entry in walker {
        match entry {
            Ok(entry) => {
                if entry.file_type().is_file() {
                    let path = entry.path();
                    println!("Found file: {}", path.display());
                } else {
                    println!("Skipping directory: {}", entry.path().display());
                }
            },
            Err(e) => {
                eprintln!("Error accessing path: {}", e);
            }
        }
    }

    Ok(())
}
